import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { Product } from '../../core/models';
import { CartService } from '../../core/services/cart.service';
import { MoneyPipe } from '../../shared/money.pipe';

@Component({
  selector: 'app-product-detail',
  standalone: true,
  imports: [CommonModule, RouterLink, MoneyPipe],
  templateUrl: './product-detail.component.html',
  styleUrls: ['./product-detail.component.css'],
})
export class ProductDetailComponent {
  private route = inject(ActivatedRoute);
  private cart = inject(CartService);

  // Backend-provided data — declared as a signal per the mockup data contract (GET /api/products/:id).
  products = signal<Product[]>([
    {
      id: 'p-1',
      name: 'Aurora Wireless Headphones',
      description:
        'Over-ear noise-cancelling headphones with 30-hour battery life, plush memory-foam ear cushions, and multipoint Bluetooth pairing. Includes a hard-shell travel case and USB-C fast charging.',
      priceCents: 12999,
      imageUrl: 'https://picsum.photos/seed/aurora/800/600',
      stockQty: 24,
    },
    {
      id: 'p-2',
      name: 'Nimbus Mechanical Keyboard',
      description:
        'Hot-swappable 75% mechanical keyboard with PBT double-shot keycaps, gasket-mounted plate, and per-key RGB. Connects over USB-C or 2.4GHz wireless.',
      priceCents: 8900,
      imageUrl: 'https://picsum.photos/seed/nimbus/800/600',
      stockQty: 12,
    },
    {
      id: 'p-3',
      name: 'Terra Insulated Bottle 1L',
      description:
        'Double-walled stainless steel bottle keeps drinks cold for 24 hours or hot for 12. Leak-proof lid with an integrated carry handle. BPA-free and dishwasher safe.',
      priceCents: 3200,
      imageUrl: 'https://picsum.photos/seed/terra/800/600',
      stockQty: 60,
    },
    {
      id: 'p-4',
      name: 'Lumen LED Desk Lamp',
      description:
        'Dimmable LED desk lamp with five color temperatures, a wireless charging base, and a USB-C pass-through port. Flicker-free and eye-care certified.',
      priceCents: 4500,
      imageUrl: 'https://picsum.photos/seed/lumen/800/600',
      stockQty: 0,
    },
    {
      id: 'p-5',
      name: 'Pulse Fitness Tracker',
      description:
        'Water-resistant fitness tracker with continuous heart-rate, SpO2, and sleep monitoring. Seven-day battery life and 40+ workout modes.',
      priceCents: 7999,
      imageUrl: 'https://picsum.photos/seed/pulse/800/600',
      stockQty: 5,
    },
    {
      id: 'p-6',
      name: 'Vertex Laptop Backpack',
      description:
        'Weatherproof 22L backpack with a padded 16-inch laptop sleeve, hidden anti-theft pocket, and a luggage pass-through strap. Made from recycled ripstop nylon.',
      priceCents: 6400,
      imageUrl: 'https://picsum.photos/seed/vertex/800/600',
      stockQty: 33,
    },
  ]);

  readonly productId = toSignal(this.route.paramMap.pipe(map((p) => p.get('id'))), {
    initialValue: null,
  });

  readonly product = computed<Product | null>(
    () => this.products().find((p) => p.id === this.productId()) ?? null,
  );

  quantity = signal(1);
  added = signal(false);

  increment(): void {
    const max = this.product()?.stockQty ?? 1;
    this.quantity.update((q) => Math.min(q + 1, Math.max(max, 1)));
  }

  decrement(): void {
    this.quantity.update((q) => Math.max(1, q - 1));
  }

  addToCart(): void {
    const p = this.product();
    if (!p || p.stockQty === 0) return;
    this.cart.addProduct(p, this.quantity());
    this.added.set(true);
  }
}
